noncompliant_example:
uint32_t calculate_true_altitude(void);
void process_radar(void) {
    uint16_t target_alt = calculate_true_altitude();
}

compliant_example:
uint32_t calculate_true_altitude(void);
void process_radar(void) {
    uint32_t raw_alt = calculate_true_altitude();
    uint16_t target_alt = 0U;
    if (raw_alt <= 65535U) {
        target_alt = (uint16_t)raw_alt;
    } else {
        target_alt = 65535U;
    }
}
